    int n;
    cin >> n;
    string s;
    cin >> s;
    stringstream ss(s);
    string word;
    string result;
    while(ss >> word){
        reverse(word.begin(), word.end());
        result += word + ' ';
    }
    result.pop_back();
    cout << result << endl;
    return 0;
